248	export function createMcpServer(services: ServiceDefinition[], iconUrl: string, upstreamTimeoutMs = 30_000, requestId?: string): McpServer {
249	  const server = new McpServer({
250	    name: "vmhq-mcp",
251	    version: "0.1.0",
252	    icons: [
253	      {
254	        src: iconUrl,
255	        mimeType: "image/png",
256	      },
257	    ],
258	  });
259	
260	  server.tool(
261	    "vmhq_status",
262	    "Return VMHQ MCP status, enabled services and disabled services. This tool is always available even when no service APIs are configured.",
263	    {
264	      ping: z.boolean().optional().describe("If true, attempt a lightweight GET to each enabled service to verify it is reachable. Uses a 3 s timeout regardless of the service timeout setting."),
265	    },
266	    { title: "VMHQ Status" },
267	    async ({ ping }: { ping?: boolean }) => {
268	      const PING_TIMEOUT_MS = 3_000;
269	      const enabled = services.map((service) => service.id);
270	      const disabled = (Object.keys(API_CATALOGS) as ServiceId[]).filter((serviceId) => !enabled.includes(serviceId));
271	
272	      let pingResults: Record<string, unknown> | undefined;
273	
274	      if (ping) {
275	        const entries = await Promise.all(
276	          services.map(async (service) => {
277	            if (!service.pingPath) {
278	              return [service.id, { status: "skipped", reason: "no_ping_path" }] as const;
279	            }
280	            const start = performance.now();
281	            const result = await callService(
282	              service,
283	              { method: "GET", path: service.pingPath },
284	              { timeoutMs: PING_TIMEOUT_MS, operationId: "ping", requestId },
285	            );
286	            const durationMs = Math.round(performance.now() - start);
287	            const res = result as Record<string, unknown>;
288	            if (res.error) {
289	              const err = res.error as Record<string, unknown>;
290	              if (err.type === "upstream_timeout") {
291	                return [service.id, { status: "timeout", durationMs }] as const;
292	              }
293	              // upstream_network_error = unreachable; upstream_error = HTTP non-2xx (fall through)
294	              if (err.type !== "upstream_error") {
295	                return [service.id, { status: "error", durationMs }] as const;
296	              }
297	            }
298	            const resp = (res.response ?? {}) as Record<string, unknown>;
299	            return [service.id, { status: resp.ok ? "ok" : "error", httpStatus: resp.status, durationMs }] as const;
300	          }),
301	        );
302	        pingResults = Object.fromEntries(entries);
303	      }
304	
305	      return {
306	        content: [
307	          {
308	            type: "text",
309	            text: responseText({
310	              status: "ok",
311	              enabledServices: enabled,
312	              disabledServices: disabled,
313	              ...(pingResults ? { ping: pingResults } : {}),
314	              iconUrl,
315	            }),
316	          },
317	        ],
318	      };
319	    },
320	  );
321	
322	  for (const service of services) {
323	    server.tool(
324	      `${service.id}_api_reference`,
325	      `Return the documented ${service.title} API operations known by this MCP server, including operation IDs, methods, paths, parameters and notes.`,
326	      apiReferenceSchema,
327	      { title: `${service.title} API Reference` },
328	      async ({ group, search }: { group?: string; search?: string }) => {
329	        return {
330	          content: [
331	            {
332	              type: "text",
333	              text: responseText(compactCatalog(service.id, group, search)),
334	            },
335	          ],
336	        };
337	      },
338	    );
339	
340	    server.tool(
341	      `${service.id}_operation`,
342	      `Call a documented ${service.title} operation by operationId. Use ${service.id}_api_reference first to discover valid operations and required path parameters.`,
343	      apiOperationSchema,
344	      { title: `${service.title} Operation` },
345	      async (input: {
346	        operationId: string;
347	        pathParams?: Record<string, string | number>;
348	        query?: ServiceRequestInput["query"];
349	        body?: unknown;
350	        headers?: Record<string, string>;
351	        fields?: ServiceRequestInput["fields"];
352	        maxLength?: ServiceRequestInput["maxLength"];
353	        domain?: ServiceRequestInput["domain"];
354	      }) => {
355	        const endpoint = endpointFor(service.id, input.operationId);
356	
357	        if (!endpoint) {
358	          return {
359	            content: [
360	              {
361	                type: "text",
362	                text: responseText({
363	                  error: "unknown_operation",
364	                  operationId: input.operationId,
365	                  hint: `Call ${service.id}_api_reference to list supported operation IDs.`,
366	                }),
367	              },
368	            ],
369	            isError: true,
370	          };
371	        }
372	
373	        const result = await callService(
374	          service,
375	          {
376	            method: endpoint.method,
377	            path: interpolatePath(endpoint.path, { ...service.defaultPathParams, ...input.pathParams }),
378	            query: input.query,
379	            body: operationBody(endpoint, input.body),
380	            headers: input.headers,
381	            fields: input.fields,
382	            maxLength: input.maxLength,
383	            domain: input.domain,
384	          },
385	          { timeoutMs: service.timeoutMs ?? upstreamTimeoutMs, operationId: endpoint.operationId, requestId },
386	        );
387	
388	        return {
389	          content: [
390	            {
391	              type: "text",
392	              text: responseText({
393	                operation: endpoint,
394	                result,
395	              }, input.maxLength),
396	            },
397	          ],
398	        };
399	      },
400	    );
401	
402	    server.tool(
403	      `${service.id}_request`,
404	      `Call any ${service.title} API endpoint through the configured ${service.title} base URL. Use relative paths only. Common API prefix: ${service.defaultPathPrefix}`,
405	      serviceRequestSchema,
406	      { title: `${service.title} Request` },
407	      async (input: ServiceRequestInput) => {
408	        const result = await callService(service, input, { timeoutMs: service.timeoutMs ?? upstreamTimeoutMs, requestId });
409	
410	        return {
411	          content: [
412	            {
413	              type: "text",
414	              text: responseText(result, input.maxLength),
415	            },
416	          ],
417	        };
418	      },
419	    );
420	
421	    if (service.id === "paperless") {
422	      registerPaperlessUploadTools(server, service, upstreamTimeoutMs, requestId);
423	    }
424	  }
425	
426	  return server;
427	}
